my $default_url   = $allowed_routes{$default_route};

# Retrieve the 'next' parameter (should be a route identifier, not an arbitrary URL)
my $next_param = $cgi->param('next');

# Sanitize: strip whitespace and ensure it's a simple alphanumeric/underscore identifier
my $redirect_url;

if (defined $next_param) {
    # Remove any leading/trailing whitespace
    $next_param =~ s/^\s+|\s+$//g;

    # Validate that the parameter is a safe route identifier (alphanumeric and underscores only)
    if ($next_param =~ /^[a-zA-Z0-9_]+$/ && exists $allowed_routes{$next_param}) {
